import type {
  SDUIActionHandler,
  SDUIActionResult,
} from '../models';

export const navigateHandler: SDUIActionHandler = (
  payload,
  _actionContext,
  deps,
): SDUIActionResult => {
  if (!deps.navigation) {
    return { success: false, error: 'Navigation dependency not provided' };
  }
  if (!payload?.screen || typeof payload.screen !== 'string') {
    return { success: false, error: 'Navigate action requires a "screen" string in payload' };
  }
  deps.navigation.navigate(
    payload.screen,
    payload.params as Record<string, unknown> | undefined,
  );
  return { success: true };
};

export const goBackHandler: SDUIActionHandler = (
  _payload,
  _actionContext,
  deps,
): SDUIActionResult => {
  if (!deps.navigation) {
    return { success: false, error: 'Navigation dependency not provided' };
  }
  deps.navigation.goBack();
  return { success: true };
};

export const replaceHandler: SDUIActionHandler = (
  payload,
  _actionContext,
  deps,
): SDUIActionResult => {
  if (!deps.navigation) {
    return { success: false, error: 'Navigation dependency not provided' };
  }
  if (!payload?.screen || typeof payload.screen !== 'string') {
    return { success: false, error: 'Replace action requires a "screen" string in payload' };
  }
  deps.navigation.replace(
    payload.screen,
    payload.params as Record<string, unknown> | undefined,
  );
  return { success: true };
};

export const deepLinkHandler: SDUIActionHandler = (
  payload,
  _actionContext,
  deps,
): SDUIActionResult => {
  if (!deps.linking) {
    return { success: false, error: 'Linking dependency not provided' };
  }
  if (!payload?.url || typeof payload.url !== 'string') {
    return { success: false, error: 'DeepLink action requires a "url" string in payload' };
  }
  deps.linking.openURL(payload.url);
  return { success: true };
};

