  1→import type { ComponentType } from 'react';
  2→
  3→// ---------------------------------------------------------------------------
  4→// SDUI — Server Driven UI Type System
  5→// RFC: .claude/rfc-conteudo-dinamico.txt
  6→// ---------------------------------------------------------------------------
  7→
  8→// ---- 3.4  Context & Interpolation ----------------------------------------
  9→
 10→export type SDUIContextValue =
 11→  | string
 12→  | number
 13→  | boolean
 14→  | null
 15→  | SDUIContext
 16→  | SDUIContextValue[];
 17→
 18→export interface SDUIContext {
 19→  [key: string]: SDUIContextValue;
 20→}
 21→
 22→// ---- 3.5  JSON Logic (subset) --------------------------------------------
 23→
 24→/**
 25→ * Accesses a value from the context using dot notation.
 26→ * @example { var: 'balance.pointsFormatted' }
 27→ */
 28→export interface SDUIVarOperator {
 29→  var: string;
 30→}
 31→
 32→export type SDUILogicPrimitive = string | number | boolean | null;
 33→export type SDUILogicOperand = SDUIVarOperator | SDUILogicPrimitive | SDUIRule | SDUIArithmeticExpression;
 34→
 35→export interface SDUIComparisonRule {
 36→  '=='?: [SDUILogicOperand, SDUILogicOperand];
 37→  '!='?: [SDUILogicOperand, SDUILogicOperand];
 38→  '>'?: [SDUILogicOperand, SDUILogicOperand];
 39→  '<'?: [SDUILogicOperand, SDUILogicOperand];
 40→  '>='?: [SDUILogicOperand, SDUILogicOperand];
 41→  '<='?: [SDUILogicOperand, SDUILogicOperand];
 42→}
 43→
 44→export interface SDUILogicalRule {
 45→  and?: SDUIRule[];
 46→  or?: SDUIRule[];
 47→  '!'?: SDUIRule;
 48→}
 49→
 50→export type SDUIRule = SDUIComparisonRule | SDUILogicalRule;
 51→
 52→export interface SDUIArithmeticExpression {
 53→  '+'?: SDUIExpressionOperand[];
 54→  '-'?: [SDUIExpressionOperand, SDUIExpressionOperand];
 55→  '*'?: SDUIExpressionOperand[];
 56→  '/'?: [SDUIExpressionOperand, SDUIExpressionOperand];
 57→  min?: SDUIExpressionOperand[];
 58→  max?: SDUIExpressionOperand[];
 59→}
 60→
 61→export type SDUIExpressionOperand =
 62→  | SDUIVarOperator
 63→  | SDUILogicPrimitive
 64→  | SDUIArithmeticExpression
 65→  | SDUIRule;
 66→
 67→/**
 68→ * A boolean value computed from a JSON Logic rule.
 69→ * Used for visibility, enabled state, or any boolean prop.
 70→ * @example { rule: { '>': [{ var: 'form.points' }, 0] } }
 71→ */
 72→export interface SDUIConditional {
 73→  rule: SDUIRule;
 74→}
 75→
 76→export interface SDUIValidationRule {
 77→  rule: SDUIRule;
 78→  message: string;
 79→}
 80→
 81→export interface SDUIValidation {
 82→  rules: SDUIValidationRule[];
 83→}
 84→
 85→// ---- 3.3  Rich Text -------------------------------------------------------
 86→
 87→export interface SDUITextNode {
 88→  type: 'text';
 89→  value: string;
 90→  bold?: boolean;
 91→  italic?: boolean;
 92→  color?: string;
 93→}
 94→
 95→export interface SDUILinkNode {
 96→  type: 'link';
 97→  text: string;
 98→  to: string;
 99→  trackEvent?: string;
100→}
101→
102→export interface SDUIIconNode {
103→  type: 'icon';
104→  name: string;
105→  color?: string;
106→  size?: number;
107→}
108→
109→export interface SDUILineBreakNode {
110→  type: 'br';
111→}
112→
113→export type SDUIRichTextChild =
114→  | SDUITextNode
115→  | SDUILinkNode
116→  | SDUIIconNode
117→  | SDUILineBreakNode;
118→
119→export interface SDUIRichText {
120→  type: 'rich_text';
121→  children: SDUIRichTextChild[];
122→}
123→
124→// ---- 3.2  Components ------------------------------------------------------
125→
126→export type SDUIPropValue =
127→  | string
128→  | number
129→  | boolean
130→  | null
131→  | SDUIConditional
132→  | SDUIValidation
133→  | SDUIRichText
134→  | SDUIPropValue[]
135→  | { [key: string]: SDUIPropValue };
136→
137→export interface SDUIComponentProps {
138→  [key: string]: SDUIPropValue;
139→}
140→
141→export interface SDUIComponent<T extends string = string> {
142→  type: T;
143→  props: SDUIComponentProps;
144→  visible?: SDUIConditional;
145→}
146→
147→// ---- 3.1  Screen Structure ------------------------------------------------
148→
149→export type SDUIHeader = SDUIComponent;
150→export type SDUIFooter = SDUIComponent;
151→
152→export interface SDUIScreen {
153→  id: string;
154→  context: SDUIContext;
155→  header?: SDUIHeader;
156→  body: SDUIComponent[];
157→  footer?: SDUIFooter;
158→}
159→
160→export interface SDUIScreenResponse {
161→  screen: SDUIScreen;
162→}
163→
164→// ---- Component Registry ---------------------------------------------------
165→
166→export type SDUIComponentRenderer<P extends SDUIComponentProps = SDUIComponentProps> =
167→  ComponentType<{
168→    props: P;
169→    context: SDUIContext;
170→    onAction?: (descriptor: SDUIActionDescriptor) => void;
171→  }>;
172→
173→export interface SDUIComponentRegistry {
174→  [type: string]: SDUIComponentRenderer;
175→}
176→
177→// ---- Known Component Types (voucher screens) ------------------------------
178→
179→export const SDUI_KNOWN_TYPES = [
180→  'heading',
181→  'text',
182→  'balance_display',
183→  'points_input',
184→  'button',
185→  'link',
186→  'alert',
187→  'list_text_icon',
188→  'separator',
189→  'icon_text_row',
190→  'section_heading',
191→  'nav_header',
192→  'rich_text',
193→  'voucher_card',
194→  'empty_state',
195→  'points_card',
196→  'tab_bar',
197→  'transaction_item',
198→  'date_separator',
199→  'detail_header',
200→  'tag_label',
201→  'key_value_row',
202→  'card_activity',
203→] as const;
204→
205→export type SDUIKnownType = (typeof SDUI_KNOWN_TYPES)[number];
206→
207→// ---- Action Handler System ------------------------------------------------
208→
209→export const SDUI_ACTION_TYPES = [
210→  'navigate',
211→  'goBack',
212→  'replace',
213→  'deepLink',
214→  'fetch',
215→  'submit',
216→  'retry',
217→  'setValue',
218→  'setComputed',
219→  'useAll',
220→  'open',
221→  'close',
222→  'trackScreenView',
223→  'trackSelect',
224→  'trackModalView',
225→  'setState',
226→  'reset',
227→  'openURL',
228→  'phoneCall',
229→] as const;
230→
231→export type SDUIActionType = (typeof SDUI_ACTION_TYPES)[number];
232→
233→export interface SDUIActionDescriptor<
234→  T extends string = string,
235→  P extends Record<string, unknown> = Record<string, unknown>,
236→> {
237→  type: T;
238→  payload?: P;
239→}
240→
241→export type SDUINavigateAction = SDUIActionDescriptor<
242→  'navigate',
243→  { screen: string; params?: Record<string, unknown> }
244→>;
245→export type SDUIGoBackAction = SDUIActionDescriptor<'goBack'>;
246→export type SDUIReplaceAction = SDUIActionDescriptor<
247→  'replace',
248→  { screen: string; params?: Record<string, unknown> }
249→>;
250→export type SDUIDeepLinkAction = SDUIActionDescriptor<'deepLink', { url: string }>;
251→
252→export type SDUIFetchAction = SDUIActionDescriptor<
253→  'fetch',
254→  { service: string; method: string; params?: Record<string, unknown> }
255→>;
256→export type SDUISubmitAction = SDUIActionDescriptor<
257→  'submit',
258→  { service: string; method: string; payload: Record<string, unknown> }
259→>;
