import type {
  SDUIActionHandler,
  SDUIActionResult,
  SDUIArithmeticExpression,
} from '../models';
import { evaluateExpression } from '../utils/jsonLogic';
import { resolveContextPath } from '../utils/interpolation';

function setAtPath(
  obj: Record<string, unknown>,
  path: string,
  value: unknown,
): Record<string, unknown> {
  const segments = path.split('.');
  if (segments.length === 1) {
    return { ...obj, [segments[0]]: value };
  }

  const [head, ...rest] = segments;
  const child = (obj[head] ?? {}) as Record<string, unknown>;
  return {
    ...obj,
    [head]: setAtPath(
      typeof child === 'object' && child !== null
        ? { ...child }
        : {},
      rest.join('.'),
      value,
    ),
  };
}

function getAtPath(
  obj: Record<string, unknown>,
  path: string,
): unknown {
  const resolved = resolveContextPath(
    obj as Parameters<typeof resolveContextPath>[0],
    path,
  );
  return resolved;
}

export const setValueHandler: SDUIActionHandler = (
  payload,
  actionContext,
): SDUIActionResult => {
  if (!payload?.contextKey || typeof payload.contextKey !== 'string') {
    return { success: false, error: 'setValue requires a "contextKey" string in payload' };
  }

  if (!('value' in payload)) {
    return { success: false, error: 'setValue requires a "value" in payload' };
  }

  actionContext.setForm(prev =>
    setAtPath(prev, payload.contextKey as string, payload.value),
  );

  return { success: true };
};

export const setComputedHandler: SDUIActionHandler = (
  payload,
  actionContext,
): SDUIActionResult => {
  if (!payload?.contextKey || typeof payload.contextKey !== 'string') {
    return { success: false, error: 'setComputed requires a "contextKey" string in payload' };
  }

  if (!payload.formula || typeof payload.formula !== 'object') {
    return { success: false, error: 'setComputed requires a "formula" object in payload' };
  }

  const mergedContext = {
    ...actionContext.screen,
    form: actionContext.form as Parameters<typeof evaluateExpression>[1],
  };

  const computed = evaluateExpression(
    payload.formula as SDUIArithmeticExpression,
    mergedContext,
  );

  actionContext.setForm(prev =>
    setAtPath(prev, payload.contextKey as string, computed),
  );

  return { success: true, data: computed };
};

export const useAllHandler: SDUIActionHandler = (
  payload,
  actionContext,
): SDUIActionResult => {
  if (!payload?.sourceKey || typeof payload.sourceKey !== 'string') {
    return { success: false, error: 'useAll requires a "sourceKey" string in payload' };
  }

  if (!payload?.targetKey || typeof payload.targetKey !== 'string') {
    return { success: false, error: 'useAll requires a "targetKey" string in payload' };
  }

  const mergedContext = {
    ...actionContext.screen,
    form: actionContext.form,
  };

  const sourceValue = getAtPath(
    mergedContext as Record<string, unknown>,
    payload.sourceKey as string,
  );

  actionContext.setForm(prev =>
    setAtPath(prev, payload.targetKey as string, sourceValue),
  );

  return { success: true, data: sourceValue };
};

