import React, { useState, useCallback, useRef } from 'react';
import { View, ScrollView } from 'react-native';
import { Text, Box, Button, SeparatorHorizontal } from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIActionDescriptor, SDUIActionContext, SDUIActionDeps } from '../services/sdui/models';
import {
  executeAction,
  getDefaultActionRegistry,
} from '../services/sdui/actions';

interface ActionLogEntry {
  id: number;
  type: string;
  payload?: Record<string, unknown>;
  result: { success: boolean; error?: string; data?: unknown };
  timestamp: string;
}

function FormStateActionsDemo() {
  const [log, setLog] = useState<ActionLogEntry[]>([]);
  const [formState, setFormState] = useState<Record<string, unknown>>({});
  const idRef = useRef(0);

  const registry = useRef(getDefaultActionRegistry()).current;

  const actionContext: SDUIActionContext = {
    screen: {
      balance: { pointsQuantity: 15320 } as Record<string, unknown>,
      conversion: { factor: 0.01 } as Record<string, unknown>,
    },
    form: formState,
    setForm: (updater) => {
      setFormState(prev => {
        const next = updater(prev);
        return next;
      });
    },
  };

  const deps: SDUIActionDeps = {};

  const fire = useCallback(async (descriptor: SDUIActionDescriptor) => {
    const ctx: SDUIActionContext = {
      ...actionContext,
      form: formState,
      setForm: (updater) => {
        setFormState(prev => {
          const next = updater(prev);
          return next;
        });
      },
    };

    const result = await executeAction(registry, descriptor, ctx, deps);
    idRef.current += 1;
    const entry: ActionLogEntry = {
      id: idRef.current,
      type: descriptor.type,
      payload: descriptor.payload,
      result: { success: result.success, error: result.error, data: result.data },
      timestamp: new Date().toLocaleTimeString(),
    };
    setLog(prev => [entry, ...prev].slice(0, 20));
  }, [formState]);

  return (
    <ScrollView style={{ flex: 1 }}>
      <Box p="xxxs">
        <Text type="headingMDL" mb="nano">
          SDUI Form State Actions
        </Text>
        <Text type="bodySM" color="INTENSE_COLOR_03" mb="xs">
          Demonstrates setValue, setComputed, and useAll action handlers.
          Form state is displayed live below.
        </Text>

        <View style={{
          backgroundColor: '#F5F5F5',
          borderRadius: 8,
          padding: 12,
          marginBottom: 16,
        }}>
          <Text type="subtitleXXL" mb="nano">Form State (live)</Text>
          <Text type="bodySM" style={{ fontFamily: 'monospace' }}>
            {JSON.stringify(formState, null, 2) || '{}'}
          </Text>
        </View>

        <View style={{
          backgroundColor: '#E3F2FD',
          borderRadius: 8,
          padding: 12,
          marginBottom: 16,
        }}>
          <Text type="subtitleXXL" mb="nano">Screen Context (immutable)</Text>
          <Text type="bodySM" style={{ fontFamily: 'monospace' }}>
            {JSON.stringify(actionContext.screen, null, 2)}
          </Text>
        </View>

        <SeparatorHorizontal mv="xs" />

        <Text type="subtitleXXL" mb="nano">setValue</Text>
        <Box mb="xs" style={{ gap: 8 }}>
          <Button
            text="Set points = 5000"
            onPress={() => fire({
              type: 'setValue',
              payload: { contextKey: 'points', value: 5000 },
            })}
          />
          <Button
            text="Set points = 10000"
            onPress={() => fire({
              type: 'setValue',
              payload: { contextKey: 'points', value: 10000 },
            })}
          />
          <Button
            text='Set nested user.name = "Alice"'
            onPress={() => fire({
              type: 'setValue',
              payload: { contextKey: 'user.name', value: 'Alice' },
            })}
          />
        </Box>

        <SeparatorHorizontal mv="xs" />

        <Text type="subtitleXXL" mb="nano">setComputed</Text>
        <Text type="bodySM" color="INTENSE_COLOR_03" mb="nano">
          Uses JSON Logic arithmetic. Set points first, then compute reais.
        </Text>
        <Box mb="xs" style={{ gap: 8 }}>
          <Button
            text="Compute reais = points * 0.01"
            onPress={() => fire({
              type: 'setComputed',
              payload: {
                contextKey: 'reais',
                formula: { '*': [{ var: 'form.points' }, { var: 'conversion.factor' }] },
              },
            })}
          />
          <Button
            text="Compute discount = points + 500"
            onPress={() => fire({
              type: 'setComputed',
              payload: {
                contextKey: 'discount',
                formula: { '+': [{ var: 'form.points' }, 500] },
              },
            })}
          />
        </Box>

        <SeparatorHorizontal mv="xs" />

        <Text type="subtitleXXL" mb="nano">useAll</Text>
        <Text type="bodySM" color="INTENSE_COLOR_03" mb="nano">
          Copies a value from context (screen or form) to a form key.
        </Text>
        <Box mb="xs" style={{ gap: 8 }}>
          <Button
            text="Use all points (balance → form.points)"
            onPress={() => fire({
              type: 'useAll',
              payload: {
                sourceKey: 'balance.pointsQuantity',
                targetKey: 'points',
              },
            })}
          />
          <Button
            text="Copy form.points → form.maxUsed"
            onPress={() => fire({
              type: 'useAll',
              payload: {
                sourceKey: 'form.points',
                targetKey: 'maxUsed',
              },
            })}
          />
        </Box>

        <SeparatorHorizontal mv="xs" />

        <Text type="subtitleXXL" mb="nano">Error Cases</Text>
        <Box mb="xs" style={{ gap: 8 }}>
          <Button
            text="setValue without contextKey (error)"
            variant="secondary"
            onPress={() => fire({
              type: 'setValue',
              payload: { value: 123 },
            })}
          />
          <Button
            text="setComputed without formula (error)"
            variant="secondary"
            onPress={() => fire({
              type: 'setComputed',
              payload: { contextKey: 'foo' },
            })}
          />
          <Button
            text="useAll without targetKey (error)"
            variant="secondary"
            onPress={() => fire({
              type: 'useAll',
              payload: { sourceKey: 'balance.pointsQuantity' },
            })}
          />
        </Box>

        <SeparatorHorizontal mv="xs" />

        <Text type="subtitleXXL" mb="nano">
          Action Log ({log.length})
        </Text>
        {log.length === 0 && (
          <Text type="bodySM" color="INTENSE_COLOR_03">
            Press a button above to see results here.
          </Text>
        )}
        {log.map(entry => (
          <View
            key={entry.id}
            style={{
              backgroundColor: entry.result.success ? '#E8F5E9' : '#FFEBEE',
              borderRadius: 8,
              padding: 10,
              marginBottom: 6,
            }}
          >
            <Text type="bodySM">
              [{entry.timestamp}] {entry.type} → {entry.result.success ? 'SUCCESS' : 'FAILED'}
            </Text>
            {entry.payload && (
              <Text type="bodySM" color="INTENSE_COLOR_03">
                {JSON.stringify(entry.payload)}
              </Text>
            )}
            {entry.result.data !== undefined && (
              <Text type="bodySM" color="DEEP_COLOR_SEMANTICS_04">
                data: {JSON.stringify(entry.result.data)}
              </Text>
            )}
            {entry.result.error && (
              <Text type="bodySM" color="DEEP_COLOR_SEMANTICS_02">
                {entry.result.error}
              </Text>
            )}
          </View>
        ))}
      </Box>
    </ScrollView>
  );
}

const meta: Meta = {
  title: 'SDUI/Form State Actions',
  component: FormStateActionsDemo,
};

export default meta;

type Story = StoryObj<typeof meta>;

export const Demo: Story = {};

