const defaultActionRegistry: SDUIActionRegistry = {
  navigate: navigateHandler,
  goBack: goBackHandler,
  replace: replaceHandler,
  deepLink: deepLinkHandler,
  setValue: setValueHandler,      // ✅ Correct
