    );
    expect(result.success).toBe(false);
    expect(result.error).toContain('__proto__');
    expect(({}as any).polluted).toBeUndefined();
  });

  it('rejects constructor pollution', () => {
    const ctx = createActionContext();
    const result = setValueHandler(
      { contextKey: 'constructor.prototype.polluted', value: 'bad' },
      ctx,
      emptyDeps,
    );
    expect(result.success).toBe(false);
  });

  it('rejects empty contextKey', () => {
    const ctx = createActionContext();
    const result = setValueHandler({ contextKey: '', value: 123 }, ctx, emptyDeps);
    expect(result.success).toBe(false);
  });

  it('rejects paths with empty segments', () => {
    const ctx = createActionContext();
    const result = setValueHandler(
      { contextKey: 'user..email', value: 'x' },
      ctx,
