import type {
  SDUIActionContext,
  SDUIActionDeps,
} from '../models';
import {
  setValueHandler,
  setComputedHandler,
  useAllHandler,
} from './formState';
import { createActionRegistry, executeAction } from './registry';

let capturedForm: Record<string, unknown> = {};
const mockSetForm = jest.fn((updater: (prev: Record<string, unknown>) => Record<string, unknown>) => {
  capturedForm = updater(capturedForm);
});

function createActionContext(
  overrides?: Partial<SDUIActionContext>,
): SDUIActionContext {
  return {
    screen: {},
    form: {},
    setForm: mockSetForm,
    ...overrides,
  };
}

const emptyDeps: SDUIActionDeps = {};

beforeEach(() => {
  capturedForm = {};
  mockSetForm.mockClear();
});

describe('setValueHandler', () => {
  it('sets a simple key in form state', () => {
    const ctx = createActionContext();
    const result = setValueHandler(
      { contextKey: 'points', value: 5000 },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(true);
    expect(mockSetForm).toHaveBeenCalledTimes(1);
    expect(capturedForm).toEqual({ points: 5000 });
  });

  it('sets a nested key in form state', () => {
    capturedForm = { user: { name: 'Alice' } };
    const ctx = createActionContext({ form: capturedForm });
    const result = setValueHandler(
      { contextKey: 'user.email', value: 'alice@test.com' },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(true);
    expect(capturedForm).toEqual({
      user: { name: 'Alice', email: 'alice@test.com' },
    });
  });

  it('sets value to null', () => {
    const ctx = createActionContext();
    const result = setValueHandler(
      { contextKey: 'field', value: null },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(true);
    expect(capturedForm).toEqual({ field: null });
  });

  it('sets value to string', () => {
    const ctx = createActionContext();
    const result = setValueHandler(
      { contextKey: 'name', value: 'hello' },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(true);
    expect(capturedForm).toEqual({ name: 'hello' });
  });

  it('fails when contextKey is missing', () => {
    const ctx = createActionContext();
    const result = setValueHandler({ value: 123 }, ctx, emptyDeps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('contextKey');
  });

  it('fails when contextKey is not a string', () => {
    const ctx = createActionContext();
    const result = setValueHandler(
      { contextKey: 42, value: 123 },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(false);
    expect(result.error).toContain('contextKey');
  });

  it('fails when value is missing from payload', () => {
    const ctx = createActionContext();
    const result = setValueHandler({ contextKey: 'foo' }, ctx, emptyDeps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('value');
  });

  it('fails when payload is undefined', () => {
    const ctx = createActionContext();
    const result = setValueHandler(undefined, ctx, emptyDeps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('contextKey');
  });
});

describe('setComputedHandler', () => {
  it('computes arithmetic from formula and sets in form', () => {
    const ctx = createActionContext({
      form: { points: 5000 },
      screen: { conversion: { factor: 0.01 } },
    });
    capturedForm = { points: 5000 };

    const result = setComputedHandler(
      {
        contextKey: 'reais',
        formula: { '*': [{ var: 'form.points' }, { var: 'conversion.factor' }] },
      },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(true);
    expect(result.data).toBe(50);
    expect(capturedForm).toEqual({ points: 5000, reais: 50 });
  });

  it('computes addition', () => {
    const ctx = createActionContext({ form: { a: 10, b: 20 } });
    capturedForm = { a: 10, b: 20 };

    const result = setComputedHandler(
      {
        contextKey: 'sum',
        formula: { '+': [{ var: 'form.a' }, { var: 'form.b' }] },
      },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(true);
    expect(result.data).toBe(30);
    expect(capturedForm).toEqual({ a: 10, b: 20, sum: 30 });
  });

  it('computes with literal values', () => {
    const ctx = createActionContext();

    const result = setComputedHandler(
      {
        contextKey: 'result',
        formula: { '*': [100, 0.01] },
      },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(true);
    expect(result.data).toBe(1);
    expect(capturedForm).toEqual({ result: 1 });
  });

  it('handles division by zero (returns 0)', () => {
    const ctx = createActionContext();

    const result = setComputedHandler(
      {
        contextKey: 'result',
        formula: { '/': [100, 0] },
      },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(true);
    expect(result.data).toBe(0);
  });

  it('fails when contextKey is missing', () => {
    const ctx = createActionContext();
    const result = setComputedHandler(
      { formula: { '+': [1, 2] } },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(false);
    expect(result.error).toContain('contextKey');
  });

  it('fails when formula is missing', () => {
    const ctx = createActionContext();
    const result = setComputedHandler(
      { contextKey: 'foo' },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(false);
    expect(result.error).toContain('formula');
  });

  it('fails when formula is not an object', () => {
    const ctx = createActionContext();
    const result = setComputedHandler(
      { contextKey: 'foo', formula: 'not-an-object' },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(false);
    expect(result.error).toContain('formula');
  });

  it('fails when payload is undefined', () => {
    const ctx = createActionContext();
    const result = setComputedHandler(undefined, ctx, emptyDeps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('contextKey');
  });
});

describe('useAllHandler', () => {
  it('copies value from screen context to form', () => {
    const ctx = createActionContext({
      screen: { balance: { pointsQuantity: 15320 } },
    });

    const result = useAllHandler(
      { sourceKey: 'balance.pointsQuantity', targetKey: 'points' },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(true);
    expect(result.data).toBe(15320);
    expect(capturedForm).toEqual({ points: 15320 });
  });

  it('copies value from form to another form key', () => {
    capturedForm = { points: 5000 };
    const ctx = createActionContext({ form: capturedForm });

    const result = useAllHandler(
      { sourceKey: 'form.points', targetKey: 'maxPoints' },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(true);
    expect(result.data).toBe(5000);
    expect(capturedForm).toEqual({ points: 5000, maxPoints: 5000 });
  });

  it('handles missing source (resolves to empty string)', () => {
    const ctx = createActionContext({ screen: {} });

    const result = useAllHandler(
      { sourceKey: 'nonexistent.path', targetKey: 'target' },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(true);
    expect(result.data).toBe('');
    expect(capturedForm).toEqual({ target: '' });
  });

  it('fails when sourceKey is missing', () => {
    const ctx = createActionContext();
    const result = useAllHandler(
      { targetKey: 'foo' },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(false);
    expect(result.error).toContain('sourceKey');
  });

  it('fails when targetKey is missing', () => {
    const ctx = createActionContext();
    const result = useAllHandler(
      { sourceKey: 'foo' },
      ctx,
      emptyDeps,
    );

    expect(result.success).toBe(false);
    expect(result.error).toContain('targetKey');
  });

  it('fails when payload is undefined', () => {
    const ctx = createActionContext();
    const result = useAllHandler(undefined, ctx, emptyDeps);

    expect(result.success).toBe(false);
    expect(result.error).toContain('sourceKey');
  });
});

describe('integration with ActionRegistry', () => {
  it('form handlers work with executeAction via registry', async () => {
    const setFormFn = jest.fn((updater: (prev: Record<string, unknown>) => Record<string, unknown>) => {
      updater({});
    });

    const ctx: SDUIActionContext = {
      screen: { balance: { pointsQuantity: 10000 } },
      form: {},
      setForm: setFormFn,
    };

    let registry = createActionRegistry();
    registry = {
      ...registry,
      setValue: setValueHandler,
      setComputed: setComputedHandler,
      useAll: useAllHandler,
    };

    const setResult = await executeAction(
      registry,
      { type: 'setValue', payload: { contextKey: 'points', value: 3000 } },
      ctx,
      emptyDeps,
    );
    expect(setResult.success).toBe(true);
    expect(setFormFn).toHaveBeenCalledTimes(1);

    const computeResult = await executeAction(
      registry,
      {
        type: 'setComputed',
        payload: {
          contextKey: 'reais',
          formula: { '*': [3000, 0.01] },
        },
      },
      ctx,
      emptyDeps,
    );
    expect(computeResult.success).toBe(true);
    expect(computeResult.data).toBe(30);

    const useAllResult = await executeAction(
      registry,
      {
        type: 'useAll',
        payload: {
          sourceKey: 'balance.pointsQuantity',
          targetKey: 'maxPoints',
        },
      },
      ctx,
      emptyDeps,
    );
    expect(useAllResult.success).toBe(true);
    expect(useAllResult.data).toBe(10000);
  });
});

